import 'dart:io'; void main() { final files = Directory('lib').listSync(recursive: true).whereType<File>().where((f) => f.path.endsWith('_provider.dart')); for (var f in files) { var content = f.readAsStringSync(); var newContent = content.replaceAll(RegExp(r'@riverpod\s+class'), '@Riverpod(keepAlive: true)\nclass'); if (content != newContent) { f.writeAsStringSync(newContent); print('Updated \'); } } }
